/**
 * ---header-docs-section---
 * # yummies/device
 *
 * ## Description
 *
 * Lightweight user-agent sniffing for product UI: mobile/tablet heuristics and a normalized UA
 * string accessor. These checks are best-effort (browsers spoof and evolve) and should gate only
 * non-critical layout or analytics, never security. Prefer feature detection when the platform API
 * is what you actually need.
 *
 * ## Usage
 *
 * ```ts
 * import { checkIsMobileDevice, getUserAgent } from "yummies/device";
 * ```
 */
/**
 * Returns the normalized user agent string in lowercase.
 *
 * @example
 * ```ts
 * const userAgent = getUserAgent();
 * ```
 */
declare const getUserAgent: () => any;
/**
 * Detects whether the current device should be treated as mobile based on the user agent.
 *
 * @example
 * ```ts
 * const isMobile = checkIsMobileDevice();
 * ```
 */
declare const checkIsMobileDevice: () => boolean;
/**
 * Detects whether the current device should be treated as a tablet based on the user agent.
 *
 * @example
 * ```ts
 * const isTablet = checkIsTabletDevice();
 * ```
 */
declare const checkIsTabletDevice: () => boolean;
/**
 * Detects whether the current device supports a touch-first form factor.
 *
 * @example
 * ```ts
 * const isTouch = checkIsTouchDevice();
 * ```
 */
declare const checkIsTouchDevice: () => boolean;
declare const isMobileDevice: boolean;
declare const isTabletDevice: boolean;
declare const isTouchDevice: boolean;

export { checkIsMobileDevice, checkIsTabletDevice, checkIsTouchDevice, getUserAgent, isMobileDevice, isTabletDevice, isTouchDevice };
